3_real_world_example.code:
// Synchronous callback — called immediately
function withLogging(label, fn) {
  console.log(`▶ ${label}`);
  const result = fn(); // calls your callback right now
  console.log(` ${label} done`);
  return result;
}

const area = withLogging('Area calculation', () => 5 * 8);
console.log(area); // 40

// Asynchronous callback — called later
function delayedGreet(name, callback) {
  setTimeout(() => {
    callback(`Hello, ${name}!`); // called after 1s, via Event Loop
  }, 1000);
}

delayedGreet('SkillSprint', (msg) => console.log(msg)); // 'Hello, SkillSprint!' after 1s

